INSERT INTO `cms` (`id`, `title`, `ar_title`, `description`, `ar_description`, `type`, `status`, `flag`, `position`, `image`, `ar_image`, `created_on`, `updated_on`, `created_by`, `updated_by`) VALUES
(1, 'What is CFC Platform ?', 'ما هي منصة التنافسية المالية؟', 'CFC is a digital lending platform that connects established businesses with investor (lenders). The platform uses technology to connect both parties through the principle of crowdfunding, - i.e. raising small amounts of funds from many individuals.', '<div style=\"text-align: justify;\"><span style=\"font-size: 1rem;\">منصة التنافسية المالية هي منصة إقراض رقمية تربط الشركات القائمة بالمستثمرين (المقرضين). تستخدم المنصة التكنولوجيا لربط الطرفين من خلال مبدأ التمويل الجماعي ، أي جمع مبالغ صغيرة من الأموال من العديد من الأفراد.</span></div>', 9, 1, NULL, NULL, 'dsd', '', '2022-11-14 06:17:43', '2022-11-14 06:17:43', 0, 0),
(2, 'How can I know the times of offering opportunities?', 'كيف يمكن معرفة أوقات طرح الفرص؟', 'You can follow up on the offer of opportunities by visiting CFC platform, as well as if you are registered on the platform, you will be notified by e-mail periodically of the opportunities.', 'يمكنك متابعة طرح الفرص من خلال زيارتك للمنصة، وكذلك اذا كنت مسجلا بالمنصة سوف يتم اشعارك ببريد الكتروني بشكل دوري للفرص المطروحه.', 9, 1, NULL, NULL, NULL, '', '2022-11-14 06:42:38', '2022-11-14 06:42:38', 1, 0),
(3, 'What is meant by the term \'KYC\'?', 'KYC ما المقصود بمصطلح', 'The term KYC stands for “Know Your Customer” and is used throughout the client identification process. The pre-set KYC rules by Capital Market Authority (CMA) are the standard requirements that need to be followed by all regulated entities. This includes identity verification, proof of address, employment information, and other general information. Investors need to clear all KYC requirements prior to being onboarded on the CFC platform. The compliance department will conduct ongoing KYC checks to ensure information is constantly updated.', 'يشير مصطلح \"معرفة العميل\" للقواعد المحددة مسبقًا من قبل هيئة السوق المالية في المملكة العربية السعودية، ويستخدم طوال عملية تحديد هوية العميل. وهي المتطلبات القياسية التي يجب اتباعها من قبل جميع الكيانات الخاضعة للتنظيم. يتضمن ذلك التحقق من الهوية وإثبات العنوان ومعلومات التوظيف والمعلومات العامة الأخرى. يحتاج المستثمرون إلى معرفة جميع متطلبات \"معرفة العميل\" قبل الانضمام إلى منصة التنافسية المالية. سيجري قسم الامتثال فحوصات \"معرفة العميل\" المستمرة لضمان تحديث المعلومات باستمرار.', 9, 1, NULL, NULL, NULL, '', '2022-11-15 11:37:08', '2022-11-15 11:37:08', 1, 0),
(5, 'What measures are in place to ensure security around my data and the integrity of your platform?', 'ماهي الإجراءات المتخذة لضمان حماية بياناتي الخاصة ولحماية النظام في المنصة؟', 'CFC Platform has been developed on our proprietary server. CFC Platform has leveraged the “best in breed” security features such as encryption, identity and access management, and network security. These features are applied across the whole platform from the holding of data, application access, web communications, and back office operations. We are committed to implement and continuously improve security-aware software development, operational management, and threat-mitigation practices that are essential to the strong protection of services and data', 'تم تطوير منصة التنافسية المالية على الخادم الخاص بنا. استخدمت التنافسية المالية أعلى ميزات الأمان \"الأفضل في فئتها\" مثل التشفير وإدارة الهوية والوصول وأمن الشبكة. ويتم تطبيق هذه الميزات عبر النظام الأساسي بأكمله بدءًا من الاحتفاظ بالبيانات والوصول إلى التطبيقات واتصالات الويب والعمليات الداخلية. ونحن ملتزمون بالتنفيذ والتحسين المستمر وتطوير البرامج المحسنة للأمان ، والإدارة التشغيلية، وممارسات التخفيف من التهديدات التي تعتبر ضرورية لحماية قوية للخدمات والبيانات.', 9, 1, NULL, NULL, NULL, '', '2022-11-21 07:28:52', '2022-11-21 07:28:52', 1, 0),
(6, 'What is Sukuk?', 'ما هي الصكوك؟', 'Sukuk are securities issued by companies (or governments) to raise funds from investors for a specified period of time with a specified repayment date, during which period the sukuk usually distribute a profit rate (fixed or variable) periodically. At the end of the life of the instrument, known as the maturity period, the issuer of the security (the borrower) repays the capital raised from the investors.', '<div style=\"text-align: justify;\"><span style=\"font-size: 1rem;\">الصكوك&nbsp; هي أوراق مالية تصدرها&nbsp; الشركات (أو الحكومات)&nbsp; لجمع الأموال من المستثمرين لفترة زمنية محددة بتاريخ سداد محدد، وخلال هذه الفترة عادةً ما توزع الصكوك معدل ربح (ثابت أو متغير) بشكل دوري. وفي نهاية عمر الصك، المعروفة بفترة الاستحقاق، يقوم مصدر الورقة المالية (المقترض) بسداد رؤوس الأموال التي تم جمعها من المستثمرين.</span></div>', 9, 1, NULL, NULL, NULL, '', '2022-11-21 07:28:53', '2022-11-21 07:28:53', 1, 0),
(7, 'How do I make profit?', 'كيف أحصل على الأرباح من هذه الفرص؟', 'Each investment opportunity has a different distribution timing from the other, such as if it is quarterly, semi-annually, or paid in one payment, which is the maturity period at the end of the life of the instrument.', '<div style=\"text-align: justify;\"><span style=\"font-size: 1rem;\">لكل ﻓﺮﺻﺔ استثمارية توقيت توزيع مختلف عن الأخرى، كأن يكون رﺑﻊ ﺳﻨﻮي أو ﻧﺼﻒ ﺳﻨﻮي أو تسدد دﻓﻌﺔ واحدة، وهي فترة الاستحقاق في نهاية عمر الصك.</span></div>', 9, 1, NULL, NULL, NULL, '', '2022-11-21 07:28:54', '2022-11-21 07:28:54', 1, 0),
(8, '100% Shariah Compliance', '100٪ متوافق مع أحكام الشريعة', '.', '.', 8, 1, NULL, NULL, 'https://firebasestorage.googleapis.com/v0/b/cfcsa-3a0a2.appspot.com/o/Kyc%2FISLAMIC1.SVG1676376308167?alt=media&token=72af0aae-cf56-4100-bca6-d3d2171fbc3e', 'https://firebasestorage.googleapis.com/v0/b/cfcsa-3a0a2.appspot.com/o/Kyc%2FISLAMIC1.SVG1676376309515?alt=media&token=3c992df1-494a-4470-986f-c8f90cfdff79', '2022-11-21 07:28:56', '2022-11-21 07:28:56', 1, 0),
(9, 'Loan terms from 1- 36 months', 'مرونه مدروسة لمدة التمويل', '.', '.', 8, 1, NULL, NULL, 'https://firebasestorage.googleapis.com/v0/b/cfcsa-3a0a2.appspot.com/o/Kyc%2Fsec9-2.svg1676368659765?alt=media&token=35ca3a45-9c29-448c-8503-bac7e69d9d4c', 'https://firebasestorage.googleapis.com/v0/b/cfcsa-3a0a2.appspot.com/o/Kyc%2Fsec9-2.svg1676368660873?alt=media&token=999ad345-0c4b-4fa8-9b83-d7dc07c896d7', '2022-11-21 07:31:40', '2022-11-21 07:31:40', 1, 0),
(10, 'Financing as quick as 1 day', 'السرعه في اجراءات التمويل', '.', '.', 8, 1, NULL, NULL, 'https://firebasestorage.googleapis.com/v0/b/cfcsa-3a0a2.appspot.com/o/Kyc%2Fsec9-2.svg1676368935338?alt=media&token=1bfaada0-630b-4e97-830f-f8282bd26336', 'https://firebasestorage.googleapis.com/v0/b/cfcsa-3a0a2.appspot.com/o/Kyc%2Fsec9-2.svg1676368936323?alt=media&token=234e845b-a502-42d1-90c3-6986c05f99ec', '2022-11-21 07:31:42', '2022-11-21 07:31:42', 1, 0),
(11, 'Customised loans that fits your needs', 'تمويل بسمات مخصصة تناسب احتياجاتك', '.', '.', 8, 1, NULL, NULL, 'https://firebasestorage.googleapis.com/v0/b/cfcsa-3a0a2.appspot.com/o/Kyc%2Fsec9-3.svg1676368959967?alt=media&token=50fc9b9e-75ee-46be-958c-b01e0fbc8038', 'https://firebasestorage.googleapis.com/v0/b/cfcsa-3a0a2.appspot.com/o/Kyc%2Fsec9-3.svg1676368960913?alt=media&token=f8445949-b72e-4d9d-8239-b64633a1b389', '2022-11-21 07:38:16', '2022-11-21 07:38:16', 1, 0),
(12, 'Enter Details', 'ادخال التفاصيل', 'Provide your contact information and login your account to start the process.', 'ادخل معلومات الاتصال الخاصه بك ثم قم بتسجيل الدخول في الحساب وابدأ العمليه.', 5, 1, NULL, NULL, 'https://firebasestorage.googleapis.com/v0/b/cfcsa-3a0a2.appspot.com/o/Kyc%2Fsec3-1.svg1676368417333?alt=media&token=08ab9371-7e72-43c2-85d1-bf87cbf8328b', 'https://firebasestorage.googleapis.com/v0/b/cfcsa-3a0a2.appspot.com/o/Kyc%2Fsec3-1.svg1676368418578?alt=media&token=dc00d69f-0297-476d-af97-a67d55479282', '2022-11-21 09:02:21', '2022-11-21 09:02:21', 1, 0),
(13, 'Verify by KYC', 'التحقق من البيانات', 'Provide your national ID number and your full name for the KYC verification purpose.', 'أدخل رقم هويتك الوطنية/الرقم المعرف/السجل التجاري واسمك الكامل لغرض التحقق من بياناتك&nbsp;', 5, 1, NULL, NULL, 'https://firebasestorage.googleapis.com/v0/b/cfcsa-3a0a2.appspot.com/o/Kyc%2Fsec3-2.svg1676368430488?alt=media&token=56b33f33-6579-4030-badf-7df439a808cf', 'https://firebasestorage.googleapis.com/v0/b/cfcsa-3a0a2.appspot.com/o/Kyc%2Fsec3-2.svg1676368431417?alt=media&token=797c74cf-bfe2-446d-9e8f-041fec2a1d74', '2022-11-21 09:02:23', '2022-11-21 09:02:23', 1, 0),
(14, 'Get Approval', 'الحصول على الموافقة', 'Submit your KYC and personal details and get approval within 24hrs.', 'بعد تقديم البيانات والتحقق منها ستحصل على الموافقة المبدئية في غضون 24 ساعة', 5, 1, NULL, NULL, 'https://firebasestorage.googleapis.com/v0/b/cfcsa-3a0a2.appspot.com/o/Kyc%2Fsec3-3.svg1676368447214?alt=media&token=26b2f1d8-cb5a-48a2-8c86-c2c1dbe5c8c3', 'https://firebasestorage.googleapis.com/v0/b/cfcsa-3a0a2.appspot.com/o/Kyc%2Fsec3-3.svg1676368448078?alt=media&token=f29a5f96-9694-4c68-9b96-5efa5a5fcc39', '2022-11-21 09:02:24', '2022-11-21 09:02:24', 1, 0),
(15, 'Borrower', 'طالب التمويل', 'Planning to raise money for your business? Checkout our hassle free options for you.', '<div style=\"direction: rtl;\"><span style=\"font-size: 1rem;\">هل تخطط لتمويل مشروعك ؟ سجل في منصة التنافسية المالية</span></div>', 1, 1, NULL, NULL, 'https://firebasestorage.googleapis.com/v0/b/cfcsa-3a0a2.appspot.com/o/Kyc%2Fmoon.svg1676366950358?alt=media&token=3510419e-9c15-48e1-bc1d-e5622308eef3', 'https://firebasestorage.googleapis.com/v0/b/cfcsa-3a0a2.appspot.com/o/Kyc%2Fmoon2.svg1676366951356?alt=media&token=b421e562-2b7e-4e6b-80b8-4a1bfc784786', '2022-11-21 09:27:13', '2022-11-21 09:27:13', 1, 0),
(16, 'Investor', 'مستثمر', 'Invest in fast growing businesses with us, 100% safe and secure investment platform in Saudi arabia.', 'استثمر في اعمال سريعة النمو.', 1, 1, NULL, NULL, 'https://firebasestorage.googleapis.com/v0/b/cfcsa-3a0a2.appspot.com/o/Kyc%2Fmoon-2.svg1676367098344?alt=media&token=566e80c1-d118-40f6-8ee4-45c67f6735a3', 'https://firebasestorage.googleapis.com/v0/b/cfcsa-3a0a2.appspot.com/o/Kyc%2Fmoon-22.svg1676367099469?alt=media&token=83dd32cb-5b3d-4ed0-9f2e-b24842062430', '2022-11-21 09:27:14', '2022-11-21 09:27:14', 1, 0),
(17, 'General', 'معلومات', 'Explore CFC website for info, suggestions and advise on crowdfunding and investment.', 'استكشف منصة التنافسية للحصول على معلومات واقتراحات ونصائح حول التمويل الجماعي والاستثمار', 1, 1, NULL, NULL, 'https://firebasestorage.googleapis.com/v0/b/cfcsa-3a0a2.appspot.com/o/Kyc%2Fmoon-3.svg1676367284704?alt=media&token=2ee799d6-1709-41bf-bccc-589fc8a0b8a2', 'https://firebasestorage.googleapis.com/v0/b/cfcsa-3a0a2.appspot.com/o/Kyc%2Fmoon-3.svg1676367286206?alt=media&token=c780e315-fbaf-4fab-ba19-5b484c502895', '2022-11-21 09:27:16', '2022-11-21 09:27:16', 1, 0),
(18, 'What makes us different?', 'ما الذي يجعلنا مختلفين ؟', 'The Financial Competitiveness Team harnesses its expertise in the credit analysis of projects based on quantitative and qualitative analysis of the feasibility of the project and the company, its management and its financial statements, to reach the rating scale for investment risks. After that, the debt instrument, which is the sukuk, is issued, in which the investment is made.', '<span style=\"text-align: justify;\">يسخر فريق التنافسية المالية خبراته في التحليل الائتماني للمشاريع بناءً على التحليل الكمي والنوعي لجدوى المشروع والشركة وإدارتها وبياناتها المالية ، للوصول إلى مقياس تصنيف مخاطر الاستثمار. بعد ذلك يتم إصدار أداة الدين وهي الصكوك التي يتم الاستثمار فيها.</span>', 2, 1, NULL, NULL, 'https://firebasestorage.googleapis.com/v0/b/cfcsa-3a0a2.appspot.com/o/Kyc%2Fabout-us%20(1).svg1676368544743?alt=media&token=2ad46a97-5cc8-4eac-a61b-5f0480f468aa', 'https://firebasestorage.googleapis.com/v0/b/cfcsa-3a0a2.appspot.com/o/Kyc%2Fabout-us.svg1676377427064?alt=media&token=a630fc96-7214-4668-929d-5f7133ea6e6a', '2022-11-21 09:35:01', '2022-11-21 09:35:01', 1, 0),
(19, '100% Shariah Compliance', '100٪ متوافق مع أحكام الشريعة', '.', '.', 3, 1, NULL, NULL, 'https://firebasestorage.googleapis.com/v0/b/cfcsa-3a0a2.appspot.com/o/Kyc%2Ffeature-1.svg1676368027449?alt=media&token=f526137e-3db9-4934-b500-4400046d9334', 'https://firebasestorage.googleapis.com/v0/b/cfcsa-3a0a2.appspot.com/o/Kyc%2Ffeature-1.svg1676368028827?alt=media&token=d85bc852-526f-4de5-9cfe-3739d0d63219', '2022-11-21 09:37:58', '2022-11-21 09:37:58', 1, 0),
(20, 'Free promotion for your campaign', 'ترويج مجاني لحملتك', '.', '.', 3, 1, NULL, NULL, 'https://firebasestorage.googleapis.com/v0/b/cfcsa-3a0a2.appspot.com/o/Kyc%2Ffeature-2.svg1676367871821?alt=media&token=e9d16037-30f7-4218-beb5-0f52d8f85fbb', 'https://firebasestorage.googleapis.com/v0/b/cfcsa-3a0a2.appspot.com/o/Kyc%2Ffeature-2.svg1676367872768?alt=media&token=c21500f8-59be-4c70-afe9-5810cf2acac0', '2022-11-21 09:37:59', '2022-11-21 09:37:59', 1, 0),
(21, 'withdraw your amount instantly', 'السحب الفوري للمستحقات', '.', '.', 3, 1, NULL, NULL, 'https://firebasestorage.googleapis.com/v0/b/cfcsa-3a0a2.appspot.com/o/Kyc%2Ffeature-3.svg1676367856723?alt=media&token=16af4dee-d841-45b1-80c4-02d6d7ac2bae', 'https://firebasestorage.googleapis.com/v0/b/cfcsa-3a0a2.appspot.com/o/Kyc%2Ffeature-3.svg1676367857612?alt=media&token=3d0def35-b31c-4bf5-82d9-5fbfbb2a6a80', '2022-11-21 09:38:00', '2022-11-21 09:38:00', 1, 0),
(22, 'Competitiveness Financial Company (CFC) was established in September 2021, and the Competitiveness obtained a financial technology permit in securities business from the Capital Market Authority (CMA) in June 2022, to offer and invest in debt instruments.', 'تأسست شركة التنافسية المالية في سبتمبر 2021م، وحصلت التنافسية على تصريح التقنية المالية في أعمال الأوراق المالية​ من هيئة السوق المالية في يونيه 2022م، لطرح أدوات الدين والاستثمار فيها.', 'Competitiveness Financial is an electronic platform for crowdfunding, which aims to connect investors with investment opportunities to finance projects, by arranging the issuance and offering of debt instruments to finance projects of small and medium-sized companies, which in turn contribute to raising the GDP and providing jobs, and presenting those opportunities in the platform to investors and clients Platform.\nCMA had launched the Financial Technology Lab in 2018, in order to keep pace with the accelerating technological revolution in the financial market. The financial technology system in the Kingdom is highly attractive, allowing companies to easily provide innovative services.\nCFC is one of the international technology competitiveness companies. It is a national institution that aims to provide integrated technical consultancy to government organizations and bodies and participate in restructuring systems and procedures to enhance access to the goals of the vision of the Kingdom of Saudi Arabia.', '<p class=\"MsoNormal\" dir=\"RTL\" style=\"outline-style: initial; outline-width: 0px; margin-right: 18pt; text-align: justify; line-height: normal; direction: rtl; unicode-bidi: embed;\"><span lang=\"AR-JO\" style=\"outline-style: initial; outline-width: 0px; font-family: Arial, &quot;sans-serif&quot;;\">التنافسية المالية هي منصة إلكترونية للتمويل الجماعي، تهدف إلى وصل المستثمرين بالفرص الاستثمارية لتمويل المشاريع، من خلال ترتيب إصداروطرح أدوات الدين لتمويل مشاريع الشركات الصغيرة والمتوسطة، اﻟﺘﻲ ﺗﺴﺎﻫﻢ بدورها ﻓﻲ رﻓﻊ اﻟﻨﺎﺗﺞ اﻟﻤﺤﻠﻲ الإجمالي و ﺗﻮﻓﻴﺮ الوظائف، وعرض تلك الفرص في المنصة على المستثمرين عملاء المنصة.&nbsp;<o:p style=\"outline-style: initial; outline-width: 0px;\"></o:p></span></p><p style=\"outline-style: initial; outline-width: 0px; text-align: right; direction: rtl;\"></p><p class=\"MsoNormal\" dir=\"RTL\" style=\"outline-style: initial; outline-width: 0px; margin-right: 18pt; text-align: justify; line-height: normal; direction: rtl; unicode-bidi: embed;\"><span lang=\"AR-JO\" style=\"outline-style: initial; outline-width: 0px; font-family: Arial, &quot;sans-serif&quot;;\">ويقوم فريق عمل التنافسية المالية بتسخير خبراته في التحليل الائتماني لمشاريع الشركات بناء على التحليل الكمي والتحليل النوعي لجدوى المشروع والشركة وإدارتها وقوائمها المالية، للوصول إلى النطاق التصنيفي لمخاطر الاستثمار. بعد ذلك، يتم إصدار أداة الدين وهي الصكوك، التي يتم الاستثمار فيها.&nbsp; &nbsp;</span></p>', 4, 1, NULL, NULL, 'https://firebasestorage.googleapis.com/v0/b/cfcsa-3a0a2.appspot.com/o/Kyc%2F11.jpeg1676368270585?alt=media&token=b74f9c3c-7d78-4139-b8c0-b6553aed3e6b', 'https://firebasestorage.googleapis.com/v0/b/cfcsa-3a0a2.appspot.com/o/Kyc%2Ftrust%20AR.JPG1676375986312?alt=media&token=13538ef8-9197-4a02-89fd-40a1767f3d1e', '2022-11-21 09:39:56', '2022-11-21 09:39:56', 1, 0),
(23, 'Whether You  Are Borrower to Fund raise or an  Investor .', 'سواء طالب تمويل او مستثمر', '<h3 style=\"text-align: justify; \">Please register in Competitiveness Financial platform and let our professional team and tools complete your application.</h3>', '<h2 style=\"text-align: right;\">تفضل بالتسجيل بمنصة<br>التنافسية المالية ودع<br>&nbsp;فريقنا وادواتنا الاحترافية<br>بدراسة طلبك</h2>', 6, 1, NULL, NULL, 'https://firebasestorage.googleapis.com/v0/b/cfcsa-3a0a2.appspot.com/o/Kyc%2Fabout-us%20(1).svg1676377507608?alt=media&token=9a7bfc24-84f7-4834-bd0e-26916971174e', 'https://firebasestorage.googleapis.com/v0/b/cfcsa-3a0a2.appspot.com/o/Kyc%2Fabout-us.svg1676377509400?alt=media&token=f28f8e23-d049-4604-a75d-ca5e74deaae9', '2022-11-22 06:12:01', '2022-11-22 06:12:01', 1, 0),
(24, 'How to start your fundraiser on Competitiveness Financial.', 'كيف تبدأ عملية التمويل على منصة التنافسية المالية', '', '', 5, 1, 1, NULL, NULL, '', '2022-12-08 09:09:11', '2022-12-08 09:09:11', 1, 0),
(25, 'Exceptional value', 'قيمة استثنائية', 'With competitiveness financial , you as an investor / borrower, deserve to be in our equation.', 'مع التنافسية المالية انت كمستثمر او طالب تمويل تستحق ان تكون في معادلتنا', 7, 1, NULL, NULL, NULL, '', '2022-12-08 09:30:05', '2022-12-08 09:30:05', 1, 0),
(26, 'Funding made simple, rewarding & fun', 'أصبح التمويل ميسرا ومجزٍ', '', '', 8, 1, 1, NULL, NULL, '', '2022-12-08 09:31:12', '2022-12-08 09:31:12', 1, 0),
(27, 'A promising future vision to contribute to the financial sector in the Kingdom of Saudi Arabia', 'رؤية مستقبلية واعدة للمساهمة في القطاع المالي في المملكة العربية السعودية', 'through innovative and distinguished technical financial solutions for investment and financing.', 'من خلال إبتكارنا حلول في التقنية المالية وكسب ثقة المستثمرين والشركاء', 0, 1, NULL, NULL, 'https://firebasestorage.googleapis.com/v0/b/cfcsa-3a0a2.appspot.com/o/Kyc%2Fmain%20vedeo-with%20logo.mp41676366263156?alt=media&token=14ab0006-2f5e-4a43-a8d2-68ec74a5da51', 'https://firebasestorage.googleapis.com/v0/b/cfcsa-3a0a2.appspot.com/o/Kyc%2Fmain%20vedeo-with%20logo.mp41676366510195?alt=media&token=650f730d-1412-4c8c-8ce5-0f0404d22a11', '2022-12-08 09:36:36', '2022-12-08 09:36:36', 1, 0);
