INSERT INTO `pages` (`id`, `title`, `ar_title`, `pages_type_id`, `description`, `ar_description`, `status`, `position`, `created_at`, `updated_at`) VALUES
(1, 'إشعار الخصوصية', 'إشعار الخصوصية', 3, '<h5><p class=\"MsoNormal\" align=\"center\" dir=\"RTL\" style=\"text-align:center;direction:\nrtl;unicode-bidi:embed\"><b><span lang=\"AR-SA\" style=\"font-size:12.0pt;line-height:\n107%;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;mso-ascii-theme-font:major-bidi;\nmso-hansi-theme-font:major-bidi;mso-bidi-theme-font:major-bidi\"><br></span></b></p><p class=\"MsoNormal\" align=\"center\" dir=\"RTL\" style=\"text-align:center;direction:\nrtl;unicode-bidi:embed\"><b><span lang=\"AR-SA\" style=\"font-size:12.0pt;line-height:\n107%;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;mso-ascii-theme-font:major-bidi;\nmso-hansi-theme-font:major-bidi;mso-bidi-theme-font:major-bidi\">إشعار الخصوصية</span></b></p><p class=\"MsoNormal\" align=\"center\" dir=\"RTL\" style=\"text-align:center;direction:\nrtl;unicode-bidi:embed\"><b><span lang=\"AR-SA\" style=\"font-size:12.0pt;line-height:\n107%;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;mso-ascii-theme-font:major-bidi;\nmso-hansi-theme-font:major-bidi;mso-bidi-theme-font:major-bidi\"><br></span></b><b><span dir=\"LTR\" style=\"font-size:12.0pt;line-height:107%;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;\nmso-ascii-theme-font:major-bidi;mso-hansi-theme-font:major-bidi;mso-bidi-theme-font:\nmajor-bidi\"><o:p></o:p></span></b></p>\n\n<p class=\"MsoNormal\" dir=\"RTL\" style=\"text-align:justify;text-justify:kashida;\ntext-kashida:20%;direction:rtl;unicode-bidi:embed\"><span lang=\"AR-SA\" style=\"font-size:12.0pt;line-height:107%;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;\nmso-ascii-theme-font:major-bidi;mso-hansi-theme-font:major-bidi;mso-bidi-theme-font:\nmajor-bidi\">يصف إشعار الخصوصية هذا كيف شركة التنافسية </span><span lang=\"AR-KW\" style=\"font-size:12.0pt;line-height:107%;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;\nmso-ascii-theme-font:major-bidi;mso-hansi-theme-font:major-bidi;mso-bidi-theme-font:\nmajor-bidi;mso-bidi-language:AR-KW\">المالية </span><span lang=\"AR-SA\" style=\"font-size:12.0pt;line-height:107%;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;\nmso-ascii-theme-font:major-bidi;mso-hansi-theme-font:major-bidi;mso-bidi-theme-font:\nmajor-bidi\">تجمع البيانات الشخصية وكيفية معالجتها واستخدامها وحمايتها داخل\nالمملكة العربية السعودية.<o:p></o:p></span></p>\n\n<p class=\"MsoNormal\" dir=\"RTL\" style=\"margin-top:12.0pt;text-align:justify;\ntext-justify:kashida;text-kashida:20%;direction:rtl;unicode-bidi:embed\"><b><span lang=\"AR-SA\" style=\"font-size:12.0pt;line-height:107%;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;\nmso-ascii-theme-font:major-bidi;mso-hansi-theme-font:major-bidi;mso-bidi-theme-font:\nmajor-bidi\">تعريفات:<o:p></o:p></span></b></p>\n\n<p class=\"MsoListParagraph\" dir=\"RTL\" style=\"margin-top:0in;margin-right:17.85pt;\nmargin-bottom:6.0pt;margin-left:0in;text-align:justify;text-justify:kashida;\ntext-kashida:20%;text-indent:-17.85pt;mso-list:l4 level1 lfo8;direction:rtl;\nunicode-bidi:embed\"><!--[if !supportLists]--><span lang=\"AR-SA\" style=\"font-size:\n12.0pt;line-height:107%;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;mso-ascii-theme-font:\nmajor-bidi;mso-fareast-font-family:&quot;Times New Roman&quot;;mso-fareast-theme-font:\nmajor-bidi;mso-hansi-theme-font:major-bidi;mso-bidi-theme-font:major-bidi\">أ‌.<span style=\"font-variant-numeric: normal; font-variant-east-asian: normal; font-stretch: normal; font-size: 7pt; line-height: normal; font-family: &quot;Times New Roman&quot;;\">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;\n</span></span><!--[endif]--><span dir=\"RTL\"></span><span lang=\"AR-SA\" style=\"font-size:12.0pt;line-height:107%;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;\nmso-ascii-theme-font:major-bidi;mso-hansi-theme-font:major-bidi;mso-bidi-theme-font:\nmajor-bidi\">في إشعار الخصوصية هذا، ما لم يقتضِ السياق خلاف ذلك، إن المصطلحات\nالتالية المشار إليها لها المعاني التالية</span><span dir=\"LTR\"></span><span dir=\"LTR\"></span><span dir=\"LTR\" style=\"font-size:12.0pt;line-height:107%;\nfont-family:&quot;Times New Roman&quot;,&quot;serif&quot;;mso-ascii-theme-font:major-bidi;\nmso-hansi-theme-font:major-bidi;mso-bidi-theme-font:major-bidi\"><span dir=\"LTR\"></span><span dir=\"LTR\"></span>:</span><span lang=\"AR-SA\" style=\"font-size:12.0pt;line-height:\n107%;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;mso-ascii-theme-font:major-bidi;\nmso-hansi-theme-font:major-bidi;mso-bidi-theme-font:major-bidi\"><o:p></o:p></span></p>\n\n<p class=\"MsoListParagraph\" dir=\"RTL\" style=\"margin-top:0in;margin-right:35.7pt;\nmargin-bottom:6.0pt;margin-left:0in;text-align:justify;text-justify:kashida;\ntext-kashida:20%;text-indent:-17.85pt;mso-list:l5 level1 lfo1;direction:rtl;\nunicode-bidi:embed\"><!--[if !supportLists]--><span style=\"font-size:12.0pt;\nline-height:107%;font-family:Symbol;mso-fareast-font-family:Symbol;mso-bidi-font-family:\nSymbol\">·<span style=\"font-variant-numeric: normal; font-variant-east-asian: normal; font-stretch: normal; font-size: 7pt; line-height: normal; font-family: &quot;Times New Roman&quot;;\">&nbsp;&nbsp;&nbsp;\n</span></span><!--[endif]--><span dir=\"RTL\"></span><b><span lang=\"AR-SA\" style=\"font-size:12.0pt;line-height:107%;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;\nmso-ascii-theme-font:major-bidi;mso-hansi-theme-font:major-bidi;mso-bidi-theme-font:\nmajor-bidi\">البيانات الشخصية</span></b><span lang=\"AR-SA\" style=\"font-size:12.0pt;\nline-height:107%;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;mso-ascii-theme-font:\nmajor-bidi;mso-hansi-theme-font:major-bidi;mso-bidi-theme-font:major-bidi\">:\nتعني البيانات التي قد تؤدي إلى تحديد هوية الشخص، بشكل مباشر أو غير مباشر، بما\nفي ذلك على سبيل المثال لا الحصر: الاسم الأول والاسم الأخير أو العائلة ورقم\nالهوية الوطنية السعودية والعناوين ورقم الهاتف ورقم الحساب المصرفي ورقم البطاقة الائتمانية.</span><span dir=\"LTR\" style=\"font-size:12.0pt;line-height:107%;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;\nmso-ascii-theme-font:major-bidi;mso-hansi-theme-font:major-bidi;mso-bidi-theme-font:\nmajor-bidi\"><o:p></o:p></span></p>\n\n<p class=\"MsoNormal\" dir=\"RTL\" style=\"margin-top:12.0pt;text-align:justify;\ntext-justify:kashida;text-kashida:20%;direction:rtl;unicode-bidi:embed\"><b><span lang=\"AR-SA\" style=\"font-size:12.0pt;line-height:107%;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;\nmso-ascii-theme-font:major-bidi;mso-hansi-theme-font:major-bidi;mso-bidi-theme-font:\nmajor-bidi\">البيانات الشخصية التي نجمعها:</span></b><b><span dir=\"LTR\" style=\"font-size:12.0pt;line-height:107%;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;\nmso-ascii-theme-font:major-bidi;mso-hansi-theme-font:major-bidi;mso-bidi-theme-font:\nmajor-bidi\"><o:p></o:p></span></b></p>\n\n<p class=\"MsoNormal\" dir=\"RTL\" style=\"text-align:justify;text-justify:kashida;\ntext-kashida:20%;direction:rtl;unicode-bidi:embed\"><span lang=\"AR-SA\" style=\"font-size:12.0pt;line-height:107%;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;\nmso-ascii-theme-font:major-bidi;mso-hansi-theme-font:major-bidi;mso-bidi-theme-font:\nmajor-bidi\">تختلف البيانات التي نجمعها بناءً على الغرض من استخدامها. ومع ذلك،\nفيما يلي أمثلة على البيانات التي نجمعها:</span><span dir=\"LTR\" style=\"font-size:\n12.0pt;line-height:107%;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;mso-ascii-theme-font:\nmajor-bidi;mso-hansi-theme-font:major-bidi;mso-bidi-theme-font:major-bidi\"><o:p></o:p></span></p>\n\n<p class=\"MsoListParagraphCxSpFirst\" dir=\"RTL\" style=\"margin-top:0in;margin-right:\n.5in;margin-bottom:8.0pt;margin-left:0in;mso-add-space:auto;text-align:justify;\ntext-justify:kashida;text-kashida:20%;text-indent:-.25in;mso-list:l0 level1 lfo2;\ndirection:rtl;unicode-bidi:embed\"><!--[if !supportLists]--><span style=\"font-size:\n12.0pt;line-height:107%;font-family:Symbol;mso-fareast-font-family:Symbol;\nmso-bidi-font-family:Symbol\">·<span style=\"font-variant-numeric: normal; font-variant-east-asian: normal; font-stretch: normal; font-size: 7pt; line-height: normal; font-family: &quot;Times New Roman&quot;;\">&nbsp;&nbsp;&nbsp; </span></span><!--[endif]--><span dir=\"RTL\"></span><span lang=\"AR-SA\" style=\"font-size:12.0pt;line-height:107%;\nfont-family:&quot;Times New Roman&quot;,&quot;serif&quot;;mso-ascii-theme-font:major-bidi;\nmso-hansi-theme-font:major-bidi;mso-bidi-theme-font:major-bidi\">البيانات التي يتم\nجمعها من خلال نماذج الطلبات أو الاستبيانات أو غيرها من الوثائق أو الاتصالات.\nعلى سبيل المثال لا الحصر الاسم الكامل وتاريخ الميلاد وأرقام الهوية.</span><span dir=\"LTR\" style=\"font-size:12.0pt;line-height:107%;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;\nmso-ascii-theme-font:major-bidi;mso-hansi-theme-font:major-bidi;mso-bidi-theme-font:\nmajor-bidi\"><o:p></o:p></span></p>\n\n<p class=\"MsoListParagraphCxSpMiddle\" dir=\"RTL\" style=\"margin-top:0in;margin-right:\n.5in;margin-bottom:8.0pt;margin-left:0in;mso-add-space:auto;text-align:justify;\ntext-justify:kashida;text-kashida:20%;text-indent:-.25in;mso-list:l0 level1 lfo2;\ndirection:rtl;unicode-bidi:embed\"><!--[if !supportLists]--><span style=\"font-size:\n12.0pt;line-height:107%;font-family:Symbol;mso-fareast-font-family:Symbol;\nmso-bidi-font-family:Symbol\">·<span style=\"font-variant-numeric: normal; font-variant-east-asian: normal; font-stretch: normal; font-size: 7pt; line-height: normal; font-family: &quot;Times New Roman&quot;;\">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;\n</span></span><!--[endif]--><span dir=\"RTL\"></span><span lang=\"AR-SA\" style=\"font-size:12.0pt;line-height:107%;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;\nmso-ascii-theme-font:major-bidi;mso-hansi-theme-font:major-bidi;mso-bidi-theme-font:\nmajor-bidi\">بيانات عن معاملاتك ومنتجاتك معنا، مثل نشاط الحساب واستخدام المنتجات.<o:p></o:p></span></p>\n\n<p class=\"MsoListParagraphCxSpMiddle\" dir=\"RTL\" style=\"margin-top:0in;margin-right:\n.5in;margin-bottom:8.0pt;margin-left:0in;mso-add-space:auto;text-align:justify;\ntext-justify:kashida;text-kashida:20%;text-indent:-.25in;mso-list:l0 level1 lfo2;\ndirection:rtl;unicode-bidi:embed\"><!--[if !supportLists]--><span style=\"font-size:\n12.0pt;line-height:107%;font-family:Symbol;mso-fareast-font-family:Symbol;\nmso-bidi-font-family:Symbol\">·<span style=\"font-variant-numeric: normal; font-variant-east-asian: normal; font-stretch: normal; font-size: 7pt; line-height: normal; font-family: &quot;Times New Roman&quot;;\">&nbsp;&nbsp;&nbsp; </span></span><!--[endif]--><span dir=\"RTL\"></span><span lang=\"AR-SA\" style=\"font-size:12.0pt;line-height:107%;\nfont-family:&quot;Times New Roman&quot;,&quot;serif&quot;;mso-ascii-theme-font:major-bidi;\nmso-hansi-theme-font:major-bidi;mso-bidi-theme-font:major-bidi\">البيانات التي يتم\nجمعها من خلال استخدامك لخدماتنا أو مواقعنا الإلكترونية أو تطبيقات الهواتف\nالمحمولة (مثل ملفات تعريف الارتباط).<o:p></o:p></span></p>\n\n<p class=\"MsoListParagraph\" dir=\"RTL\" style=\"margin-top:0in;margin-right:.5in;\nmargin-bottom:8.0pt;margin-left:0in;text-align:justify;text-justify:kashida;\ntext-kashida:20%;text-indent:-.25in;mso-list:l0 level1 lfo2;direction:rtl;\nunicode-bidi:embed\"><!--[if !supportLists]--><span style=\"font-size:12.0pt;\nline-height:107%;font-family:Symbol;mso-fareast-font-family:Symbol;mso-bidi-font-family:\nSymbol\">·<span style=\"font-variant-numeric: normal; font-variant-east-asian: normal; font-stretch: normal; font-size: 7pt; line-height: normal; font-family: &quot;Times New Roman&quot;;\">&nbsp;&nbsp;&nbsp;\n</span></span><!--[endif]--><span dir=\"RTL\"></span><span lang=\"AR-SA\" style=\"font-size:12.0pt;line-height:107%;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;\nmso-ascii-theme-font:major-bidi;mso-hansi-theme-font:major-bidi;mso-bidi-theme-font:\nmajor-bidi\">البيانات التي يتم تبادلها أثناء تواصلنا معك، مثل طلبات خدمة العملاء\nوالمرئيات التي تصلنا منك إما من خلال مواقعنا الإلكترونية أو تطبيقات الهاتف\nالمحمول أو حسابات وسائل التواصل الاجتماعي أو أي قنوات نستخدمها للتواصل مع\nالعملاء.</span><span dir=\"LTR\" style=\"font-size:12.0pt;line-height:107%;\nfont-family:&quot;Times New Roman&quot;,&quot;serif&quot;;mso-ascii-theme-font:major-bidi;\nmso-hansi-theme-font:major-bidi;mso-bidi-theme-font:major-bidi\"><o:p></o:p></span></p>\n\n<p class=\"MsoNormal\" dir=\"RTL\" style=\"text-align:justify;text-justify:kashida;\ntext-kashida:20%;direction:rtl;unicode-bidi:embed\"><b><span lang=\"AR-SA\" style=\"font-size:12.0pt;line-height:107%;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;\nmso-ascii-theme-font:major-bidi;mso-hansi-theme-font:major-bidi;mso-bidi-theme-font:\nmajor-bidi\">الأساس القانوني وأغراض جمع واستخدام بياناتك الشخصية:<o:p></o:p></span></b></p>\n\n<p class=\"MsoNormal\" dir=\"RTL\" style=\"text-align:justify;text-justify:kashida;\ntext-kashida:20%;direction:rtl;unicode-bidi:embed\"><span lang=\"AR-SA\" style=\"font-size:12.0pt;line-height:107%;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;\nmso-ascii-theme-font:major-bidi;mso-hansi-theme-font:major-bidi;mso-bidi-theme-font:\nmajor-bidi\">نقوم بجمع واستخدام البيانات وفقاً لما هو متطلب بناء على طبيعة الخدمات\nوالأعمال. في معظم الحالات، يتضمن أساسنا القانوني وأغراضنا، على سبيل المثال لا\nالحصر:<o:p></o:p></span></p>\n\n<p class=\"MsoListParagraphCxSpFirst\" dir=\"RTL\" style=\"margin-top:0in;margin-right:\n.75in;margin-bottom:8.0pt;margin-left:0in;mso-add-space:auto;text-align:justify;\ntext-justify:kashida;text-kashida:20%;text-indent:-.25in;mso-list:l3 level1 lfo3;\ndirection:rtl;unicode-bidi:embed\"><!--[if !supportLists]--><span style=\"font-size:\n12.0pt;line-height:107%;font-family:Symbol;mso-fareast-font-family:Symbol;\nmso-bidi-font-family:Symbol\">·<span style=\"font-variant-numeric: normal; font-variant-east-asian: normal; font-stretch: normal; font-size: 7pt; line-height: normal; font-family: &quot;Times New Roman&quot;;\">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;\n</span></span><!--[endif]--><span dir=\"RTL\"></span><span lang=\"AR-SA\" style=\"font-size:12.0pt;line-height:107%;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;\nmso-ascii-theme-font:major-bidi;mso-hansi-theme-font:major-bidi;mso-bidi-theme-font:\nmajor-bidi\">الامتثال لأية التزامات ومتطلبات صادرة عن الجهات القانونية\nوالتنظيمية داخل المملكة العربية السعودية.</span><span dir=\"LTR\" style=\"font-size:\n12.0pt;line-height:107%;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;mso-ascii-theme-font:\nmajor-bidi;mso-hansi-theme-font:major-bidi;mso-bidi-theme-font:major-bidi\"><o:p></o:p></span></p>\n\n<p class=\"MsoListParagraphCxSpMiddle\" dir=\"RTL\" style=\"margin-top:0in;margin-right:\n.75in;margin-bottom:8.0pt;margin-left:0in;mso-add-space:auto;text-align:justify;\ntext-justify:kashida;text-kashida:20%;text-indent:-.25in;mso-list:l3 level1 lfo3;\ndirection:rtl;unicode-bidi:embed\"><!--[if !supportLists]--><span style=\"font-size:\n12.0pt;line-height:107%;font-family:Symbol;mso-fareast-font-family:Symbol;\nmso-bidi-font-family:Symbol\">·<span style=\"font-variant-numeric: normal; font-variant-east-asian: normal; font-stretch: normal; font-size: 7pt; line-height: normal; font-family: &quot;Times New Roman&quot;;\">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;\n</span></span><!--[endif]--><span dir=\"RTL\"></span><span lang=\"AR-SA\" style=\"font-size:12.0pt;line-height:107%;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;\nmso-ascii-theme-font:major-bidi;mso-hansi-theme-font:major-bidi;mso-bidi-theme-font:\nmajor-bidi\">السماح لنا بتقديم المنتجات أو الخدمات.<o:p></o:p></span></p>\n\n<p class=\"MsoListParagraphCxSpMiddle\" dir=\"RTL\" style=\"margin-top:0in;margin-right:\n.75in;margin-bottom:8.0pt;margin-left:0in;mso-add-space:auto;text-align:justify;\ntext-justify:kashida;text-kashida:20%;text-indent:-.25in;mso-list: